1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Damage = { itemType: string; amount: number };
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: { cause: string; damages: Damage[] };
23	};
24	type Step = QuoteStep | ClaimStep;
25	type Customer = { yearsWithMHPCO: number };
26	type Scenario = { customer: Customer; steps: Step[] };
27	
28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	// An item's insurance value is always 10× its base premium.
31	const INSURANCE_VALUE_MULTIPLIER = 10;
32	
33	const insuranceValueFor = (type: string): number =>
34	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
35	
36	const DEDUCTIBLE = 100;
37	const CAP_MULTIPLIER = 2;
38	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
39	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
40	
41	const FIRST_INSURANCE_RATE = 0.1;
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const countByType = (items: Item[]): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
51	  }
52	  return counts;
53	};
54	
55	const groupBase = (type: string, count: number): number =>
56	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
57	    ? BLOCK_BASE_PREMIUM
58	    : count * basePremiumFor(type);
59	
60	const policyBase = (items: Item[]): number =>
61	  Array.from(countByType(items)).reduce(
62	    (total, [type, count]) => total + groupBase(type, count),
63	    0,
64	  );
65	
66	const LOYALTY_RATE = 0.2;
67	const LOYALTY_THRESHOLD_YEARS = 2;
68	const FOLLOW_UP_RATE = 0.15;
69	
70	type PolicyContext = { customer: Customer; isFollowUp: boolean };
71	
72	type PolicyModifier = {
73	  applies: (ctx: PolicyContext) => boolean;
74	  rate: number;
75	  sign: 1 | -1;
76	};
77	
78	const POLICY_MODIFIERS: PolicyModifier[] = [
79	  { applies: () => true, rate: FIRST_INSURANCE_RATE, sign: +1 },
80	  {
81	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
82	    rate: LOYALTY_RATE,
83	    sign: -1,
84	  },
85	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE, sign: -1 },
86	];
87	
88	const policyAdjustments = (base: number, ctx: PolicyContext): number =>
89	  POLICY_MODIFIERS.reduce(
90	    (total, mod) => total + (mod.applies(ctx) ? mod.sign * base * mod.rate : 0),
91	    0,
92	  );
93	
94	const CURSE_RATE = 0.5;
95	const HIGH_ENCHANTMENT_RATE = 0.3;
96	const HIGH_ENCHANTMENT_THRESHOLD = 5;
97	
98	const enchantmentLevel = (item: Item | undefined): number =>
99	  item?.enchantment ?? 0;
100	
101	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
102	  applies ? basePremiumFor(item.type) * rate : 0;
103	
104	const curseSurcharge = (item: Item): number =>
105	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
106	
107	const highEnchantmentSurcharge = (item: Item): number =>
108	  surchargeWhen(
109	    item,
110	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD,
111	    HIGH_ENCHANTMENT_RATE,
112	  );
113	
114	const itemSurcharges = (items: Item[]): number =>
115	  items.reduce(
116	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
117	    0,
118	  );
119	
120	// MHPCO always rounds money in its own favor: premiums up, payouts down.
121	const roundPremiumInFavorOfMHPCO = Math.ceil;
122	const roundPayoutInFavorOfMHPCO = Math.floor;
123	
124	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
125	  const base = policyBase(items);
126	  return roundPremiumInFavorOfMHPCO(
127	    base + itemSurcharges(items) + policyAdjustments(base, ctx) + PROCESSING_FEE,
128	  );
129	};
130	
131	const insuranceSum = (items: Item[]): number =>
132	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
133	
134	const capFor = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
135	
136	const reimbursableAmount = (amount: number, item: Item | undefined): number => {
137	  const isHighEnchantment =
138	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
139	  return isHighEnchantment ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
140	};
141	
142	const damagePayout = (damage: Damage, item: Item | undefined): number =>
143	  reimbursableAmount(damage.amount, item) - DEDUCTIBLE;
144	
145	const claimPayout = (claim: ClaimStep, items: Item[]): number =>
146	  claim.incident.damages.reduce(
147	    (sum, d) => sum + damagePayout(d, items.find((i) => i.type === d.itemType)),
148	    0,
149	  );
150	
151	type QuoteResult = { premium: number };
152	type ClaimResult = { payout: number; remainingCap: number };
153	type StepResult = QuoteResult | ClaimResult;
154	type ScenarioResult = { results: StepResult[] };
155	
156	type PolicyLedger = {
157	  registerQuote: (index: number, items: Item[]) => void;
158	  isFollowUp: () => boolean;
159	  itemsFor: (policy: number) => Item[];
160	  recordClaim: (policy: number, desiredPayout: number) => ClaimResult;
161	};
162	
163	const createPolicyLedger = (): PolicyLedger => {
164	  const remainingCaps = new Map<number, number>();
165	  const policyItems = new Map<number, Item[]>();
166	  return {
167	    registerQuote: (index, items) => {
168	      remainingCaps.set(index, capFor(items));
169	      policyItems.set(index, items);
170	    },
171	    isFollowUp: () => remainingCaps.size > 0,
172	    itemsFor: (policy) => policyItems.get(policy) ?? [],
173	    recordClaim: (policy, desiredPayout) => {
174	      const cap = remainingCaps.get(policy) ?? 0;
175	      const payout = Math.min(desiredPayout, cap);
176	      const remainingCap = cap - payout;
177	      remainingCaps.set(policy, remainingCap);
178	      return { payout, remainingCap };
179	    },
180	  };
181	};
182	
183	const handleQuote = (
184	  step: QuoteStep,
185	  index: number,
186	  customer: Customer,
187	  ledger: PolicyLedger,
188	): QuoteResult => {
189	  const ctx: PolicyContext = { customer, isFollowUp: ledger.isFollowUp() };
190	  ledger.registerQuote(index, step.items);
191	  return { premium: quotePremium(step.items, ctx) };
192	};
193	
194	const handleClaim = (step: ClaimStep, ledger: PolicyLedger): ClaimResult =>
195	  ledger.recordClaim(
196	    step.policy,
197	    roundPayoutInFavorOfMHPCO(claimPayout(step, ledger.itemsFor(step.policy))),
198	  );
199	
200	export const processScenario = (scenario: Scenario): ScenarioResult => {
201	  const ledger = createPolicyLedger();
202	  const results = scenario.steps.map((step, index) =>
203	    step.op === "quote"
204	      ? handleQuote(step, index, scenario.customer, ledger)
205	      : handleClaim(step, ledger),
206	  );
207	  return { results };
208	};
